var rm = new sn_ws.RESTMessageV2();
rm.setHttpMethod('post');
rm.setEndpoint('https://api.example.com/incidents');
rm.setRequestHeader('Content-Type', 'application/json');

var payload = {
  number: 'INC0012345',
  short_description: 'VPN outage',
  priority: '1'
};

rm.setRequestBody(JSON.stringify(payload));

var response = rm.execute();
gs.print('Status: ' + response.getStatusCode());
gs.print('Body: ' + response.getBody());

var payload = '{"incidents":[{"number":"INC0010001","short_description":"Email issue"},{"number":"INC0010002","short_description":"VPN issue"}]}';
var obj = JSON.parse(payload);

for (var i = 0; i < obj.incidents.length; i++) {
  gs.print(obj.incidents[i].number + ' - ' + obj.incidents[i].short_description);
}

(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
  var body = request.body.data || {};
  var result = {
    received_number: body.number || '',
    received_short_description: body.short_description || '',
    status: 'processed'
  };

  response.setStatus(200);
  response.setBody(result);
})(request, response);
